package com.example.mfa.security;

import com.example.mfa.mfa.BackupCodeService;
import com.example.mfa.user.UserRepository;
import org.springframework.security.authentication.AuthenticationProvider;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.authority.SimpleGrantedAuthority;
import org.springframework.stereotype.Component;

import java.util.List;

@Component
public class BackupCodeAuthenticationProvider implements AuthenticationProvider {

    private final BackupCodeService backupCodeService;
    private final UserRepository userRepository;

    public BackupCodeAuthenticationProvider(BackupCodeService backupCodeService, UserRepository userRepository) {
        this.backupCodeService = backupCodeService;
        this.userRepository = userRepository;
    }

    @Override
    public Authentication authenticate(Authentication authentication) {
        if (!(authentication instanceof BackupCodeAuthenticationToken token)) return null;

        String username = String.valueOf(token.getPrincipal());
        String code = String.valueOf(token.getCredentials());

        var user = userRepository.findByUsername(username).orElse(null);
        if (user == null || !user.isEnabled()) return null;
        if (!user.isMfaEnabled()) return null;

        boolean ok = backupCodeService.consumeBackupCode(user.getId(), code);
        if (!ok) return null;

        var auth = new BackupCodeAuthenticationToken(username, null, List.of(new SimpleGrantedAuthority("ROLE_USER")));
        auth.eraseCredentials();
        return auth;
    }

    @Override
    public boolean supports(Class<?> authentication) {
        return BackupCodeAuthenticationToken.class.isAssignableFrom(authentication);
    }
}

