package com.example.mfa.mfa;

import jakarta.transaction.Transactional;
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
import org.springframework.stereotype.Service;

import java.security.SecureRandom;
import java.time.Instant;
import java.util.ArrayList;
import java.util.List;
import java.util.Locale;

@Service
public class BackupCodeService {

    private static final int DEFAULT_CODES_COUNT = 10;
    private static final int CODE_BYTES = 10;
    private static final String ALPHABET = "23456789ABCDEFGHJKLMNPQRSTUVWXYZ";
    private final SecureRandom random = new SecureRandom();

    private final BackupCodeRepository backupCodeRepository;
    private final BCryptPasswordEncoder encoder = new BCryptPasswordEncoder(12);

    public BackupCodeService(BackupCodeRepository backupCodeRepository) {
        this.backupCodeRepository = backupCodeRepository;
    }

    public record GeneratedBackupCodes(List<String> plainCodes) { }

    @Transactional
    public GeneratedBackupCodes generateAndStoreNewCodes(Long userId) {
        backupCodeRepository.deleteByUserId(userId);

        List<String> plain = new ArrayList<>(DEFAULT_CODES_COUNT);

        for (int i = 0; i < DEFAULT_CODES_COUNT; i++) {
            String code = generateHumanCode();
            plain.add(code);

            BackupCodeEntity e = new BackupCodeEntity();
            e.setUserId(userId);
            e.setCodeHash(encoder.encode(normalize(code)));
            e.setCreatedAt(Instant.now());
            backupCodeRepository.save(e);
        }
        return new GeneratedBackupCodes(plain);
    }

    @Transactional
    public boolean consumeBackupCode(Long userId, String providedCode) {
        String normalized = normalize(providedCode);
        if (normalized.isBlank()) return false;

        var active = backupCodeRepository.findActiveByUserId(userId);
        for (var e : active) {
            if (encoder.matches(normalized, e.getCodeHash())) {
                int updated = backupCodeRepository.consume(e.getId(), Instant.now(), null);
                return updated == 1;
            }
        }
        return false;
    }

    public int remainingActiveCodes(Long userId) {
        return backupCodeRepository.findActiveByUserId(userId).size();
    }

    private String generateHumanCode() {
        byte[] bytes = new byte[CODE_BYTES];
        random.nextBytes(bytes);

        StringBuilder sb = new StringBuilder(12);
        for (int i = 0; i < 10; i++) {
            int idx = (bytes[i] & 0xFF) % ALPHABET.length();
            sb.append(ALPHABET.charAt(idx));
        }
        String raw = sb.toString();
        return raw.substring(0, 5) + "-" + raw.substring(5, 10);
    }

    private String normalize(String code) {
        if (code == null) return "";
        return code.replace("-", "")
                .replace(" ", "")
                .trim()
                .toUpperCase(Locale.ROOT);
    }
}

