package com.example.mfa.api;

import com.example.mfa.api.dto.EnableMfaResponse;
import com.example.mfa.api.dto.RegenerateBackupCodesResponse;
import com.example.mfa.mfa.BackupCodeService;
import com.example.mfa.user.UserRepository;
import org.springframework.http.HttpStatus;
import org.springframework.security.core.Authentication;
import org.springframework.web.bind.annotation.*;
import org.springframework.web.server.ResponseStatusException;

@RestController
@RequestMapping("/api/mfa")
public class MfaController {

    private final UserRepository userRepository;
    private final BackupCodeService backupCodeService;

    public MfaController(UserRepository userRepository, BackupCodeService backupCodeService) {
        this.userRepository = userRepository;
        this.backupCodeService = backupCodeService;
    }

    @PostMapping("/enable")
    public EnableMfaResponse enableMfa(Authentication authentication) {
        String username = authentication.getName();
        var user = userRepository.findByUsername(username)
                .orElseThrow(() -> new ResponseStatusException(HttpStatus.NOT_FOUND, "User not found"));

        user.setMfaEnabled(true);
        userRepository.save(user);

        var generated = backupCodeService.generateAndStoreNewCodes(user.getId());
        int remaining = backupCodeService.remainingActiveCodes(user.getId());
        return new EnableMfaResponse(true, generated.plainCodes(), remaining);
    }

    @PostMapping("/backup-codes/regenerate")
    public RegenerateBackupCodesResponse regenerate(Authentication authentication) {
        String username = authentication.getName();
        var user = userRepository.findByUsername(username)
                .orElseThrow(() -> new ResponseStatusException(HttpStatus.NOT_FOUND, "User not found"));

        if (!user.isMfaEnabled()) {
            throw new ResponseStatusException(HttpStatus.BAD_REQUEST, "MFA is not enabled");
        }

        var generated = backupCodeService.generateAndStoreNewCodes(user.getId());
        int remaining = backupCodeService.remainingActiveCodes(user.getId());
        return new RegenerateBackupCodesResponse(generated.plainCodes(), remaining);
    }

    @GetMapping("/backup-codes/remaining")
    public int remaining(Authentication authentication) {
        String username = authentication.getName();
        var user = userRepository.findByUsername(username)
                .orElseThrow(() -> new ResponseStatusException(HttpStatus.NOT_FOUND, "User not found"));
        if (!user.isMfaEnabled()) return 0;
        return backupCodeService.remainingActiveCodes(user.getId());
    }
}

