package com.example.mfa.api;

import com.example.mfa.api.dto.BackupCodeLoginRequest;
import com.example.mfa.api.dto.LoginRequest;
import com.example.mfa.api.dto.StatusResponse;
import com.example.mfa.security.BackupCodeAuthenticationToken;
import com.example.mfa.user.UserRepository;
import jakarta.validation.Valid;
import org.springframework.http.HttpStatus;
import org.springframework.security.authentication.AuthenticationManager;
import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
import org.springframework.security.core.Authentication;
import org.springframework.web.bind.annotation.*;
import org.springframework.web.server.ResponseStatusException;

@RestController
@RequestMapping("/api/auth")
public class AuthController {

    private final AuthenticationManager authenticationManager;
    private final UserRepository userRepository;

    public AuthController(AuthenticationManager authenticationManager, UserRepository userRepository) {
        this.authenticationManager = authenticationManager;
        this.userRepository = userRepository;
    }

    @PostMapping("/login")
    public StatusResponse login(@Valid @RequestBody LoginRequest req) {
        var user = userRepository.findByUsername(req.username)
                .orElseThrow(() -> new ResponseStatusException(HttpStatus.UNAUTHORIZED, "Invalid credentials"));

        Authentication auth = authenticationManager.authenticate(
                new UsernamePasswordAuthenticationToken(req.username, req.password)
        );

        if (auth == null || !auth.isAuthenticated()) {
            throw new ResponseStatusException(HttpStatus.UNAUTHORIZED, "Invalid credentials");
        }

        if (user.isMfaEnabled()) {
            return new StatusResponse("MFA_REQUIRED");
        }
        return new StatusResponse("AUTHENTICATED");
    }

    @PostMapping("/login/backup-code")
    public StatusResponse loginWithBackupCode(@Valid @RequestBody BackupCodeLoginRequest req) {
        Authentication auth = authenticationManager.authenticate(
                new BackupCodeAuthenticationToken(req.username, req.backupCode)
        );
        if (auth == null || !auth.isAuthenticated()) {
            throw new ResponseStatusException(HttpStatus.UNAUTHORIZED, "Invalid backup code");
        }
        return new StatusResponse("AUTHENTICATED");
    }
}